  console.log("╠══════════════════════════════════════════════════════════════╣");
  console.log(`║  Target: ${BASE_URL.padEnd(52)}║`);
  console.log("╚══════════════════════════════════════════════════════════════╝");

  const manifest = {};

  const phases = [
    { code: "SH-HEALTH-001", fn: createHealthcareAgent },
    { code: "SH-FIN-001", fn: createFinancialAgent },
    { code: "SH-MFG-001", fn: createManufacturingAgent },
    { code: "SH-RETAIL-001", fn: createRetailAgent },
    { code: "SH-ENERGY-001", fn: createEnergyAgent },
    { code: "SH-INS-001", fn: createInsuranceAgent },
  ];

  for (const { code, fn } of phases) {
    try {
      const result = await fn();
      manifest[code] = {
        agentId: result.agent.id,
        agentName: result.agent.name,
        skillIds: result.skills.map(s => s.id),
        runbookIds: result.runbooks.map(r => r.id),
        policyIds: result.policies.map(p => p.id),
        datasetId: result.dataset.id,
        evalSuiteId: result.evalSuite.id,
        healingPipelineId: result.pipeline.id,
      };
      console.log(`  ✓ ${code} created — Agent: ${result.agent.id}`);
    } catch (e) {
      console.error(`  ✗ ${code} failed:`, e.message);
      manifest[code] = { error: e.message };
    }
  }

  const isLocalDev = BASE_URL.includes("localhost") || BASE_URL.includes("127.0.0.1");
  const manifestPath = isLocalDev
    ? "scripts/self-healing-dev-ids.json"
    : "scripts/self-healing-prod-ids.json";
  fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));

  console.log("\n╔══════════════════════════════════════════════════════════════╗");
  console.log("║  CREATION COMPLETE                                          ║");
  console.log("╚══════════════════════════════════════════════════════════════╝");
  console.log(`\nManifest: ${manifestPath}`);
  for (const [code, data] of Object.entries(manifest)) {
    if (data.error) {
      console.log(`  ✗ ${code}: ${data.error}`);
    } else {
      console.log(`  ✓ ${code}: ${data.agentId} — ${data.agentName}`);
      console.log(`      Skills: ${data.skillIds.length} | Runbooks: ${data.runbookIds.length} | Policies: ${data.policyIds.length} | Pipeline: ${data.healingPipelineId}`);
    }
  }
